/**
 * Nav — single-spa parcel entry.
 *
 * The Nav app is not route-based. Root mounts it as a parcel into #navigation.
 * Nav owns Sidebar + Topbar; host MFEs use AppLayout (content shell) + useNavTitle.
 */
import React from 'react';
import singleSpaReact from 'single-spa-react';
import { createRoot } from 'react-dom/client';
import { installAuthFetchInterceptor } from '@linm-soft/common-components';
import NavRoot from './NavRoot';

// Idempotent — Root installs first; Nav ensures standalone ERP. Auth BFF URL from Root window.__LINM_AUTH_BFF_BASE__.
installAuthFetchInterceptor();

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: NavRoot as any,
  errorBoundary(_error: Error, _info: React.ErrorInfo, _props: unknown) {
    return <nav style={{ background: '#1e3a5f', height: '100%' }} />;
  },
  renderType: 'createRoot',
});

export const { bootstrap, mount, unmount } = lifecycles;
