import { BrowserRouter as Router, useLocation } from 'react-router-dom';
import { useShellPathname } from './hooks/useShellPathname';
import { Provider, useDispatch } from 'react-redux';
import { navigateToUrl } from 'single-spa';
import {
  Sidebar,
  Topbar,
  useResponsive,
  BREAKPOINTS,
  type NavSection,
  type NavItem,
  clearAuthTokens,
  hasValidAuthToken,
  AUTH_ACCESS_TOKEN_KEY,
  getAuthUser,
  clearAuthUser,
  AUTH_USER_STORAGE_KEY,
  clearPermissionsCache,
  GlobalToastHost,
  setUser,
} from '@linm-soft/common-components';
import {
  useUserPermissions,
  type NavMenuItemDto,
  type AppPermissionDto,
} from './hooks/useUserPermissions';
import { isPathAllowedByPermissions } from './utils/pathPermission';
import { NavTopbarNotificationSlot, NavTopbarRightActions } from './components/NavTopbarActions';
import { navStore } from './store/store';
import './styles/global.css';
import styles from './NavRoot.module.css';

const TOPBAR_HEIGHT = 72;
const AUTH_RETURN_URL_KEY = 'linm:auth:return-url';
const PUBLIC_PATHS = new Set([
  '/login',
  '/logout',
  '/session-expired',
  '/oidc-callback',
  '/oidc-silent-renew',
  '/unauthorized',
]);

// ─── Types ────────────────────────────────────────────────────────────────────

interface StoredUser {
  fullName?: string;
  role?: string;
  package?: string;
  allowedCompanyIds?: string[];
  canViewAllCompanies?: boolean;
}

const SIDEBAR_KEY = 'sidebar-collapsed-preference';

// ─── DB-driven nav builders ───────────────────────────────────────────────────

type NavItemExt = NavItem & { children?: NavItemExt[] };
type NavSectionExt = { title: string; items: NavItemExt[] };

function toNavItem(dto: NavMenuItemDto): NavItemExt {
  return { id: dto.code, label: dto.label, icon: dto.icon ?? 'fas fa-circle', path: dto.path ?? '#' };
}

function buildSectionsFromDB(navItems: NavMenuItemDto[]): NavSectionExt[] {
  const sorted = [...navItems].sort((a, b) =>
    a.sectionOrderIndex !== b.sectionOrderIndex
      ? a.sectionOrderIndex - b.sectionOrderIndex
      : a.orderIndex - b.orderIndex,
  );

  const groupMap = new Map<string, NavMenuItemDto>(
    sorted.filter((i) => i.isGroup).map((i) => [i.code, i]),
  );
  const childrenByGroup = new Map<string, NavMenuItemDto[]>();
  const orphanLeaves: NavMenuItemDto[] = [];

  for (const item of sorted.filter((i) => !i.isGroup && i.path)) {
    if (item.parentCode && groupMap.has(item.parentCode)) {
      const arr = childrenByGroup.get(item.parentCode) ?? [];
      arr.push(item);
      childrenByGroup.set(item.parentCode, arr);
    } else {
      orphanLeaves.push(item);
    }
  }

  type SectionAcc = { title: string; items: NavItemExt[]; order: number };
  const sectionAcc = new Map<string, SectionAcc>();

  const ensureSection = (title: string, order: number): NavItemExt[] => {
    const existing = sectionAcc.get(title);
    if (!existing) {
      sectionAcc.set(title, { title, items: [], order });
      return sectionAcc.get(title)!.items;
    }
    existing.order = Math.min(existing.order, order);
    return existing.items;
  };

  for (const group of [...groupMap.values()].sort((a, b) => a.orderIndex - b.orderIndex)) {
    const title = group.sectionTitle ?? 'Menu';
    const order = group.sectionOrderIndex ?? group.orderIndex;
    const children = (childrenByGroup.get(group.code) ?? [])
      .sort((a, b) => a.orderIndex - b.orderIndex)
      .map((c) => toNavItem(c));
    ensureSection(title, order).push({ ...toNavItem(group), children });
  }

  for (const leaf of orphanLeaves) {
    const title = leaf.sectionTitle ?? 'Menu';
    const order = leaf.sectionOrderIndex ?? leaf.orderIndex;
    ensureSection(title, order).push(toNavItem(leaf));
  }

  return [...sectionAcc.values()]
    .sort((a, b) => a.order - b.order || a.title.localeCompare(b.title, 'vi'))
    .map(({ title, items }) => ({ title, items }));
}

const ERP_FINANCE_PATH_PREFIXES = ['/kt', '/gt', '/tscd'];

function pathnameMatchesErpFinance(pathname: string): boolean {
  return ERP_FINANCE_PATH_PREFIXES.some(
    (p) => pathname === p || pathname.startsWith(`${p}/`),
  );
}

function normalizePath(path: string): string {
  if (!path) return '/';
  if (path === '/') return '/';
  return path.endsWith('/') ? path.slice(0, -1) : path;
}

function isPublicPath(pathname: string): boolean {
  return PUBLIC_PATHS.has(normalizePath(pathname));
}

const ADMIN_NAV_FALLBACK: NavSection[] = [
  {
    title: 'Quản trị hệ thống',
    items: [
      { id: 'admin-accounts',    label: 'Tài khoản',  icon: 'fas fa-users',      path: '/admin/accounts' },
      { id: 'admin-permissions', label: 'Phân quyền', icon: 'fas fa-shield-alt', path: '/admin/permissions' },
    ],
  },
];

function getActiveLogo(
  pathname: string,
  apps: AppPermissionDto[] | undefined,
): { icon: string; label: string } {
  if (pathname.startsWith('/admin')) {
    return { icon: 'fas fa-shield-alt', label: 'Quản trị hệ thống' };
  }
  if (pathnameMatchesErpFinance(pathname)) {
    const fin = apps?.find((a) => a.appCode === 'erp-finance');
    if (fin) return { icon: 'fas fa-calculator', label: fin.appName };
  }
  if (apps?.length) {
    const matched = [...apps]
      .filter((a) => a.uiBaseUrl)
      .sort((a, b) => (b.uiBaseUrl?.length ?? 0) - (a.uiBaseUrl?.length ?? 0))
      .find((a) => {
        const base = (a.uiBaseUrl ?? '').replace(/\/$/, '');
        return base && (pathname === base || pathname.startsWith(`${base}/`));
      });
    if (matched) return { icon: 'fas fa-th-large', label: matched.appName };
  }
  return { icon: 'fas fa-th-large', label: 'Linm' };
}

const NavInner: React.FC = () => {
  const location = useLocation();
  /** Shell URL (single-spa) — used for menu shell + permissions API currentPath. */
  const shellPathname = useShellPathname();
  const pathname = shellPathname;
  const { isMobile, isSmallDesktop } = useResponsive();
  const {
    permissions,
    loading,
    pathRefreshing,
    sectionLoadingTitles,
    sectionHasMore,
    isSectionLazy,
    loadSectionNavItems,
    loadMoreSectionNavItems,
  } = useUserPermissions(shellPathname);

  const readStoredUser = (): StoredUser | null => {
    if (!hasValidAuthToken()) return null;
    const user = getAuthUser() as StoredUser | null;
    if (!user) return null;
    return {
      fullName: user.fullName,
      role: user.role,
      package: user.package,
      allowedCompanyIds: user.allowedCompanyIds,
      canViewAllCompanies: user.canViewAllCompanies,
    };
  };

  const [user, setUser] = useState<StoredUser | null>(() => readStoredUser());

  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(() => {
    if (typeof window === 'undefined') return false;
    const w = window.innerWidth;
    if (w < BREAKPOINTS.mobile) return false;
    if (w < BREAKPOINTS.tablet) return true;
    return localStorage.getItem(SIDEBAR_KEY) === 'collapsed';
  });

  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [pageTitle, setPageTitle] = useState('');
  const [topbarAutoHidden, setTopbarAutoHidden] = useState(false);

  useEffect(() => {
    if (isSmallDesktop && !isSidebarCollapsed) {
      setIsSidebarCollapsed(true);
    } else if (!isMobile && !isSmallDesktop) {
      setIsSidebarCollapsed(localStorage.getItem(SIDEBAR_KEY) === 'collapsed');
    } else if (isMobile) {
      setIsSidebarCollapsed(false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isMobile, isSmallDesktop]);

  useEffect(() => {
    const handler = () => setIsMobileSidebarOpen((prev) => !prev);
    window.addEventListener('linm:nav:toggle-mobile', handler);
    return () => window.removeEventListener('linm:nav:toggle-mobile', handler);
  }, []);

  useEffect(() => {
    const syncUser = () => setUser(readStoredUser());
    syncUser();
    const onStorage = (e: StorageEvent) => {
      if (e.key === AUTH_USER_STORAGE_KEY || e.key === AUTH_ACCESS_TOKEN_KEY) syncUser();
    };
    window.addEventListener('storage', onStorage);
    window.addEventListener('linm:auth:changed', syncUser);
    window.addEventListener('linm:auth:token-changed', syncUser);
    return () => {
      window.removeEventListener('storage', onStorage);
      window.removeEventListener('linm:auth:changed', syncUser);
      window.removeEventListener('linm:auth:token-changed', syncUser);
    };
  }, [location.pathname]);

  useEffect(() => {
    setTopbarAutoHidden(false);
  }, [location.pathname]);

  useEffect(() => {
    const handler = (e: Event) => {
      const hidden = (e as CustomEvent<{ hidden?: boolean }>).detail?.hidden;
      if (typeof hidden === 'boolean') setTopbarAutoHidden(hidden);
    };
    window.addEventListener('linm:nav:topbar-autohide', handler);
    return () => window.removeEventListener('linm:nav:topbar-autohide', handler);
  }, []);

  useEffect(() => {
    const isLogin = location.pathname === '/login';
    const sidebarWidth = isLogin
      ? '0px'
      : isMobile
        ? '0px'
        : isSidebarCollapsed
          ? '64px'
          : '280px';
    document.documentElement.style.setProperty('--sidebar-width', sidebarWidth);

    const topbarVisiblePx = isMobile ? 64 : TOPBAR_HEIGHT;
    const topbarHeight =
      isLogin || topbarAutoHidden ? '0px' : `${topbarVisiblePx}px`;
    document.documentElement.style.setProperty('--topbar-height', topbarHeight);
    document.documentElement.dataset.topbarAutohide = topbarAutoHidden ? 'true' : 'false';
  }, [isSidebarCollapsed, isMobile, location.pathname, topbarAutoHidden]);

  useEffect(() => {
    const handler = (e: Event) => {
      const title = (e as CustomEvent<string>).detail;
      if (typeof title === 'string') setPageTitle(title);
    };
    window.addEventListener('linm:nav:set-title', handler);
    return () => window.removeEventListener('linm:nav:set-title', handler);
  }, []);

  useEffect(() => {
    setPageTitle('');
  }, [location.pathname]);

  useEffect(() => {
    const tokenExists = hasValidAuthToken();
    const currentPath = normalizePath(pathname);
    const fullCurrentUrl = `${window.location.pathname}${window.location.search}${window.location.hash}`;

    // Block all private URLs when unauthenticated and remember where to return after login.
    if (!tokenExists && !isPublicPath(currentPath)) {
      sessionStorage.setItem(AUTH_RETURN_URL_KEY, fullCurrentUrl);
      navigateToUrl('/login');
      return;
    }

    // Login success: return to previous URL if available.
    if (tokenExists && currentPath === '/login') {
      const returnUrl = sessionStorage.getItem(AUTH_RETURN_URL_KEY);
      if (returnUrl && returnUrl !== '/login') {
        sessionStorage.removeItem(AUTH_RETURN_URL_KEY);
        navigateToUrl(returnUrl);
      }
    }
  }, [pathname, location.search, location.hash]);

  useEffect(() => {
    if (!hasValidAuthToken()) return;
    if (isPublicPath(pathname)) return;
    if (pathname === '/') return;
    if (loading || pathRefreshing) return;

    const navItems = permissions?.navItems ?? [];
    const allowedPaths = permissions?.allowedPaths;
    if (!navItems.length && !allowedPaths?.length) return;

    if (
      !isPathAllowedByPermissions(pathname, navItems, allowedPaths, {
        isAdminUser: user?.role === 'admin',
      })
    ) {
      navigateToUrl('/unauthorized');
    }
  }, [pathname, loading, pathRefreshing, permissions?.navItems, permissions?.allowedPaths, user?.role]);

  const handleToggleSidebar = useCallback(() => {
    setIsSidebarCollapsed((prev) => {
      const next = !prev;
      if (!isMobile) localStorage.setItem(SIDEBAR_KEY, next ? 'collapsed' : 'expanded');
      return next;
    });
  }, [isMobile]);

  const handleNavigate = useCallback((path: string) => {
    navigateToUrl(path);
    if (isMobile) setIsMobileSidebarOpen(false);
  }, [isMobile]);

  const handleLogout = useCallback(() => {
    clearAuthTokens();
    clearAuthUser();
    clearPermissionsCache();
    navigateToUrl('/login');
  }, []);

  const isAdmin = user?.role === 'admin';

  const sections: NavSectionExt[] = useMemo(() => {
    const navItems = permissions?.navItems;

    if (pathname.startsWith('/admin')) {
      if (navItems?.length) {
        const built = buildSectionsFromDB(
          navItems.filter(
            (i) => i.isGroup || (i.path != null && i.path.startsWith('/admin')),
          ),
        );
        if (built.length) return built;
      }
      return ADMIN_NAV_FALLBACK;
    }

    if (navItems?.length) {
      return buildSectionsFromDB(navItems.filter((i) => !i.path?.startsWith('/admin')));
    }

    return [];
  }, [pathname, permissions?.navItems]);

  const { icon: logoIcon, label: logoLabel } = useMemo(
    () => getActiveLogo(pathname, permissions?.apps),
    [pathname, permissions?.apps],
  );

  const fullName = user?.fullName || 'Người dùng';
  const parts = fullName.trim().split(' ');
  const userInitials =
    parts.length >= 2
      ? (parts[parts.length - 2].charAt(0) + parts[parts.length - 1].charAt(0)).toUpperCase()
      : fullName.charAt(0).toUpperCase();

  const roleLabel =
    user?.role === 'admin'   ? 'Quản trị viên'
    : user?.role === 'manager' ? 'Quản lý'
    : user?.role === 'staff'   ? 'Nhân viên'
    : 'Người dùng';

  if (pathname === '/login') return null;

  return (
    <>
      <div className={styles.sidebarHost}>
        <Sidebar
          sections={sections as NavSection[]}
          activePath={pathname}
          userName={fullName}
          userRole={roleLabel}
          userInitials={userInitials}
          onNavigate={handleNavigate}
          onLogout={handleLogout}
          isCollapsed={isSidebarCollapsed}
          onToggleCollapse={handleToggleSidebar}
          isMobile={isMobile}
          isSmallDesktop={isSmallDesktop}
          isOpen={isMobileSidebarOpen}
          onRequestOpen={() => setIsMobileSidebarOpen(true)}
          onRequestClose={() => setIsMobileSidebarOpen(false)}
          logoIcon={logoIcon}
          logoLabel={logoLabel}
          menuSkeleton={loading && !permissions?.navItems?.length}
          sectionLoadingTitles={sectionLoadingTitles}
          sectionHasMore={sectionHasMore}
          isSectionLazy={isSectionLazy}
          onSectionExpand={loadSectionNavItems}
          onSectionLoadMore={loadMoreSectionNavItems}
        />
      </div>
      <div
        className={[styles.topbarHost, topbarAutoHidden ? styles.topbarHostHidden : ''].filter(Boolean).join(' ')}
        style={{
          left: isMobile ? 0 : isSidebarCollapsed ? 64 : 280,
        }}
      >
        <Topbar
          title={pageTitle}
          showMenuButton={isMobile}
          onMenuClick={() => setIsMobileSidebarOpen((prev) => !prev)}
          notificationSlot={
            <NavTopbarNotificationSlot onNavigate={handleNavigate} />
          }
          rightSlot={
            <NavTopbarRightActions
              onNavigate={handleNavigate}
              isAdmin={isAdmin}
              isMobile={isMobile}
              allowedCompanyIds={user?.allowedCompanyIds}
              canViewAllCompanies={user?.canViewAllCompanies}
            />
          }
        />
      </div>
    </>
  );
};

/** Sync Redux auth slice from secure storage (Home login writes tokens; Nav mounts later). */
const NavAuthHydrate: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const dispatch = useDispatch();

  useEffect(() => {
    if (!hasValidAuthToken()) return;
    const stored = getAuthUser();
    if (stored) dispatch(setUser(stored));
  }, [dispatch]);

  return <>{children}</>;
};

const NavRoot: React.FC = () => (
  <Provider store={navStore}>
    <GlobalToastHost />
    <Router>
      <NavAuthHydrate>
        <NavInner />
      </NavAuthHydrate>
    </Router>
  </Provider>
);

export default NavRoot;
