declare global {
  interface Window {
    __LINM_ENABLE_NOTIFICATION__?: boolean;
  }
}

/**
 * Build-time shell flags with Root runtime override for notification.
 * Production shell: Root must set `window.__LINM_ENABLE_NOTIFICATION__ === true` (not merely build flag).
 */
const buildEnableNotification =
  (import.meta.env.ENABLE_NOTIFICATION ?? import.meta.env.VITE_ENABLE_NOTIFICATION) === 'true';

function resolveEnableNotification(): boolean {
  if (!buildEnableNotification) return false;
  if (typeof window === 'undefined') return false;

  const rootFlag = window.__LINM_ENABLE_NOTIFICATION__;
  const isLocalDev = /localhost|127\.0\.0\.1/.test(window.location.origin);

  // Standalone Nav dev: build flag only. Prod shell: Root runtime must be explicit true.
  if (isLocalDev) return true;
  return rootFlag === true;
}

export const appSettings = {
  enableMessage: import.meta.env.VITE_ENABLE_MESSAGE === 'true',
  enableNotification: resolveEnableNotification(),
} as const;
