import { useState, useEffect, useRef, useCallback } from 'react';
import * as signalR from '@microsoft/signalr';
import {
  getAuthToken,
  hasValidAuthToken,
  writePermissionsSnapshot,
  getPermissionsCacheEntry,
  setPermissionsCacheEntry,
  clearPermissionsCache,
  type PermissionsCachePayload,
} from '@linm-soft/common-components';
import { mergeNavItems } from '../utils/mergeNavItems';

const AUTH_READY_MAX_MS = 8_000;
const AUTH_READY_POLL_MS = 50;

/** Wait until Root/Home persisted access token is readable (avoids early 401/403 on cold load). */
function waitForAuthReady(): Promise<boolean> {
  if (typeof window === 'undefined') return Promise.resolve(false);
  if (hasValidAuthToken()) return Promise.resolve(true);

  return new Promise((resolve) => {
    const deadline = Date.now() + AUTH_READY_MAX_MS;

    const finish = (ok: boolean) => {
      window.removeEventListener('linm:auth:token-changed', onToken);
      window.removeEventListener('linm:auth:changed', onToken);
      resolve(ok);
    };

    const onToken = () => {
      if (hasValidAuthToken()) finish(true);
    };

    window.addEventListener('linm:auth:token-changed', onToken);
    window.addEventListener('linm:auth:changed', onToken);

    const poll = () => {
      if (hasValidAuthToken()) {
        finish(true);
        return;
      }
      if (Date.now() >= deadline) {
        finish(false);
        return;
      }
      setTimeout(poll, AUTH_READY_POLL_MS);
    };
    poll();
  });
}

// ─── Types ────────────────────────────────────────────────────────────────────

export interface AppPermissionDto {
  appCode: string;
  appName: string;
  uiBaseUrl: string | null;
}

export interface NavMenuItemDto {
  code: string;
  label: string;
  icon: string | null;
  path: string | null;
  parentCode: string | null;
  orderIndex: number;
  isGroup: boolean;
  sectionTitle: string | null;
  sectionOrderIndex: number;
}

export interface NavSectionMetaDto {
  sectionTitle: string;
  leafCount: number;
  requiresLazyLoad: boolean;
}

export interface UserPermissionPayload {
  userId: string;
  userName: string;
  packageCodes: string[];
  apps: AppPermissionDto[];
  allowedEndpointCodes: string[];
  menuItemCodes: string[];
  permissionCodes: string[];
  /** Full route allow-list for ProtectedRoute (lazy menu may omit paths from navItems). */
  allowedPaths?: string[];
  /** Full nav item definitions from DB — optional for backward compatibility */
  navItems?: NavMenuItemDto[];
  /** Per master section: lazy only when requiresLazyLoad (leafCount >= 50 and not eager-loaded). */
  sectionNavMeta?: NavSectionMetaDto[];
  /** Default landing URL from the user's feature package(s) */
  packageDefaultUrl?: string;
  issuedAt: number;
}

export interface NavItemsPageDto {
  sectionTitle: string;
  items: NavMenuItemDto[];
  total: number;
  skip: number;
  limit: number;
  hasMore: boolean;
}

const NAV_SECTION_PAGE_SIZE = 50;

function applySectionMetaToLoadedSet(
  meta: NavSectionMetaDto[] | undefined,
  target: Set<string>,
): void {
  if (!meta?.length) return;
  for (const s of meta) {
    if (!s.requiresLazyLoad) target.add(s.sectionTitle);
  }
}

function sectionRequiresLazyLoad(
  sectionTitle: string,
  meta: NavSectionMetaDto[] | undefined,
): boolean {
  if (!meta?.length) return true;
  const row = meta.find((s) => s.sectionTitle === sectionTitle);
  return row?.requiresLazyLoad ?? true;
}

// ─── Cache helpers ─────────────────────────────────────────────────────────────

declare const __NAV_BUILD_HASH__: string | undefined;
const BUILD_HASH =
  typeof __NAV_BUILD_HASH__ !== 'undefined' ? __NAV_BUILD_HASH__ : 'dev';

const CACHE_ENABLED = import.meta.env.VITE_ENABLE_PERMISSIONS_CACHE === 'true';

function getTtlMs(): number {
  const ttl = (window as unknown as Record<string, unknown>).__LINM_PERM_TTL_MIN__;
  if (typeof ttl === 'number' && ttl > 0) return ttl * 60_000;
  return 10 * 60_000;
}

function readCache(): UserPermissionPayload | null {
  // VITE_ENABLE_PERMISSIONS_CACHE=false → no localStorage read; always refetch from API.
  // Cross-MFE snapshot (writePermissionsSnapshot) still updates guards after each fetch.
  if (!CACHE_ENABLED) return null;

  const cached = getPermissionsCacheEntry();
  if (!cached?.payload) return null;

  if (cached.buildHash !== BUILD_HASH) return null;
  if (cached.expiresAt != null && Date.now() > cached.expiresAt) return null;
  if (!cached.payload.navItems) return null;
  return cached.payload as unknown as UserPermissionPayload;
}

function persistPermissions(payload: UserPermissionPayload): void {
  writePermissionsSnapshot({
    navItems: payload.navItems,
    allowedPaths: payload.allowedPaths,
    packageDefaultUrl: payload.packageDefaultUrl,
    menuItemCodes: payload.menuItemCodes,
    permissionCodes: payload.permissionCodes,
    issuedAt: payload.issuedAt,
  } as Parameters<typeof writePermissionsSnapshot>[0]);
  writeCache(payload);
}

function markPermissionsResolved(payload: UserPermissionPayload | null): void {
  writePermissionsSnapshot(
    (payload ?? { navItems: [], allowedPaths: [] }) as Parameters<typeof writePermissionsSnapshot>[0],
  );
}

function writeCache(payload: UserPermissionPayload): void {
  if (!CACHE_ENABLED) return;
  try {
    const existing = getPermissionsCacheEntry();
    setPermissionsCacheEntry({
      ...existing,
      payload: payload as unknown as PermissionsCachePayload,
      expiresAt: Date.now() + getTtlMs(),
      buildHash: BUILD_HASH,
      ready: true,
    });
  } catch {
    // localStorage full or unavailable — silently skip
  }
}

function clearCache(): void {
  clearPermissionsCache();
}

// ─── API fetch ─────────────────────────────────────────────────────────────────

function getApiBase(): string {
  return import.meta.env.VITE_API_URL ?? '/web-bff/api/v1';
}

async function fetchPermissions(currentPath: string): Promise<UserPermissionPayload | null> {
  const ready = await waitForAuthReady();
  if (!ready) return null;

  const token = getAuthToken();
  if (!token) return null;
  const pathParam = encodeURIComponent(currentPath);
  try {
    const res = await fetch(
      `${getApiBase()}/admin/users/me/permissions?currentPath=${pathParam}`,
      { headers: { Authorization: `Bearer ${token}` } },
    );
    if (!res.ok) return null;
    const json = await res.json();
    return (json?.data ?? json) as UserPermissionPayload;
  } catch {
    return null;
  }
}

async function fetchNavItemsPage(
  sectionTitle: string,
  skip: number,
  limit: number,
  currentPath: string,
): Promise<NavItemsPageDto | null> {
  if (!hasValidAuthToken()) return null;
  const token = getAuthToken();
  if (!token) return null;
  const qs = new URLSearchParams({
    sectionTitle,
    skip: String(skip),
    limit: String(limit),
    currentPath,
  });
  try {
    const res = await fetch(
      `${getApiBase()}/admin/users/me/nav-items?${qs}`,
      { headers: { Authorization: `Bearer ${token}` } },
    );
    if (!res.ok) return null;
    const json = await res.json();
    return (json?.data ?? json) as NavItemsPageDto;
  } catch {
    return null;
  }
}

// ─── Hook ──────────────────────────────────────────────────────────────────────

export interface UseUserPermissionsResult {
  permissions: UserPermissionPayload | null;
  loading: boolean;
  /** True while refetching permissions for a route change (suppresses stale-path unauthorized). */
  pathRefreshing: boolean;
  sectionLoadingTitles: ReadonlySet<string>;
  sectionHasMore: ReadonlySet<string>;
  isSectionLazy: (sectionTitle: string) => boolean;
  loadSectionNavItems: (sectionTitle: string) => void;
  loadMoreSectionNavItems: (sectionTitle: string) => void;
  refresh: () => void;
}

export function useUserPermissions(currentPath: string): UseUserPermissionsResult {
  const [permissions, setPermissions] = useState<UserPermissionPayload | null>(() => readCache());
  const [loading, setLoading] = useState(permissions === null);
  const [pathRefreshing, setPathRefreshing] = useState(false);
  const [sectionLoadingTitles, setSectionLoadingTitles] = useState<Set<string>>(() => new Set());
  const [sectionHasMore, setSectionHasMore] = useState<Set<string>>(() => new Set());
  const sectionSkipRef = useRef<Map<string, number>>(new Map());
  const loadedSectionsRef = useRef<Set<string>>(new Set());
  const permissionsRef = useRef<UserPermissionPayload | null>(permissions);
  permissionsRef.current = permissions;
  const hubRef = useRef<signalR.HubConnection | null>(null);
  const cancelRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const mountedRef = useRef(true);
  const prevPathRef = useRef<string | null>(null);

  const applyPayload = useCallback((payload: UserPermissionPayload) => {
    applySectionMetaToLoadedSet(payload.sectionNavMeta, loadedSectionsRef.current);
    setPermissions(payload);
    persistPermissions(payload);
  }, []);

  const load = useCallback(async (force = false, path = currentPath) => {
    if (!force) {
      const cached = readCache();
      if (cached) {
        applySectionMetaToLoadedSet(cached.sectionNavMeta, loadedSectionsRef.current);
        writePermissionsSnapshot({
          navItems: cached.navItems,
          allowedPaths: cached.allowedPaths,
          packageDefaultUrl: cached.packageDefaultUrl,
          menuItemCodes: cached.menuItemCodes,
          permissionCodes: cached.permissionCodes,
          issuedAt: cached.issuedAt,
        } as Parameters<typeof writePermissionsSnapshot>[0]);
        setPermissions(cached);
        setLoading(false);
        return;
      }
    }
    const showMenuSkeleton = !permissionsRef.current;
    if (showMenuSkeleton) setLoading(true);
    loadedSectionsRef.current = new Set();
    sectionSkipRef.current = new Map();
    setSectionHasMore(new Set());

    const payload = await fetchPermissions(path);
    if (!mountedRef.current) return;
    if (payload) {
      applySectionMetaToLoadedSet(payload.sectionNavMeta, loadedSectionsRef.current);
      applyPayload(payload);
    } else if (!permissionsRef.current) {
      // First load failed — mark empty so guards wait / deny consistently.
      markPermissionsResolved(null);
    }
    // Path refetch failed: keep prior cache (allowedPaths + navItems) for route guards.
    setLoading(false);
  }, [applyPayload, currentPath]);

  const fetchSectionPage = useCallback(
    async (sectionTitle: string, skip: number) => {
      setSectionLoadingTitles((prev) => new Set(prev).add(sectionTitle));
      const page = await fetchNavItemsPage(
        sectionTitle,
        skip,
        NAV_SECTION_PAGE_SIZE,
        currentPath,
      );
      if (!mountedRef.current) return;

      setSectionLoadingTitles((prev) => {
        const next = new Set(prev);
        next.delete(sectionTitle);
        return next;
      });

      if (!page?.items?.length) return;

      setPermissions((prev) => {
        if (!prev) return prev;
        const merged: UserPermissionPayload = {
          ...prev,
          navItems: mergeNavItems(prev.navItems, page.items),
        };
        persistPermissions(merged);
        return merged;
      });

      const pageLeafCount = page.items.filter((i) => !i.isGroup).length;
      sectionSkipRef.current.set(sectionTitle, skip + pageLeafCount);

      setSectionHasMore((prev) => {
        const next = new Set(prev);
        if (page.hasMore) next.add(sectionTitle);
        else next.delete(sectionTitle);
        return next;
      });
    },
    [currentPath],
  );

  const isSectionLazy = useCallback(
    (sectionTitle: string) =>
      sectionRequiresLazyLoad(sectionTitle, permissions?.sectionNavMeta),
    [permissions?.sectionNavMeta],
  );

  const loadSectionNavItems = useCallback(
    (sectionTitle: string) => {
      if (loadedSectionsRef.current.has(sectionTitle)) return;
      loadedSectionsRef.current.add(sectionTitle);

      const lazy = sectionRequiresLazyLoad(sectionTitle, permissions?.sectionNavMeta);
      const hasSectionLeaves = (permissions?.navItems ?? []).some(
        (i) => !i.isGroup && i.sectionTitle === sectionTitle,
      );
      // Eager section but payload missing leaves (e.g. stale cache) — still fetch once.
      if (!lazy && hasSectionLeaves) return;

      sectionSkipRef.current.set(sectionTitle, 0);
      void fetchSectionPage(sectionTitle, 0);
    },
    [fetchSectionPage, permissions?.sectionNavMeta],
  );

  const loadMoreSectionNavItems = useCallback(
    (sectionTitle: string) => {
      if (!sectionRequiresLazyLoad(sectionTitle, permissions?.sectionNavMeta)) return;
      const skip = sectionSkipRef.current.get(sectionTitle) ?? NAV_SECTION_PAGE_SIZE;
      void fetchSectionPage(sectionTitle, skip);
    },
    [fetchSectionPage, permissions?.sectionNavMeta],
  );

  const refresh = useCallback(() => {
    clearCache();
    loadedSectionsRef.current = new Set();
    sectionSkipRef.current = new Map();
    setSectionHasMore(new Set());
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(true); }, 0);
  }, [load]);

  useEffect(() => {
    mountedRef.current = true;
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(); }, 0);

    const onAuthChanged = () => {
      clearCache();
      loadedSectionsRef.current = new Set();
      if (cancelRef.current) clearTimeout(cancelRef.current);
      cancelRef.current = setTimeout(() => { load(true); }, 0);
    };
    window.addEventListener('linm:auth:changed', onAuthChanged);
    window.addEventListener('linm:auth:token-changed', onAuthChanged);
    window.addEventListener('linm:company:changed', onAuthChanged);

    return () => {
      mountedRef.current = false;
      if (cancelRef.current) clearTimeout(cancelRef.current);
      window.removeEventListener('linm:auth:changed', onAuthChanged);
      window.removeEventListener('linm:auth:token-changed', onAuthChanged);
      window.removeEventListener('linm:company:changed', onAuthChanged);
    };
  }, [load]);

  useEffect(() => {
    if (!hasValidAuthToken()) return;
    if (prevPathRef.current === null) {
      prevPathRef.current = currentPath;
      return;
    }
    if (prevPathRef.current === currentPath) return;
    prevPathRef.current = currentPath;

    if (cancelRef.current) clearTimeout(cancelRef.current);
    setPathRefreshing(true);
    cancelRef.current = setTimeout(() => {
      void load(true, currentPath).finally(() => {
        if (mountedRef.current) setPathRefreshing(false);
      });
    }, 0);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentPath]);

  useEffect(() => {
    if (import.meta.env.VITE_ENABLE_SIGNALR !== 'true') return;
    const token = getAuthToken();
    if (!token) return;

    const hubUrl = (import.meta.env.VITE_AUTH_HUB_URL ?? 'http://localhost:5001') + '/hubs/permission';
    const connection = new signalR.HubConnectionBuilder()
      .withUrl(hubUrl, { accessTokenFactory: () => getAuthToken() ?? '' })
      .withAutomaticReconnect()
      .configureLogging(signalR.LogLevel.Warning)
      .build();

    connection.on('PermissionChanged', () => {
      clearCache();
      loadedSectionsRef.current = new Set();
      if (cancelRef.current) clearTimeout(cancelRef.current);
      cancelRef.current = setTimeout(() => {
        load(true).then(() => {
          window.dispatchEvent(new CustomEvent('linm:permission:changed'));
        });
      }, 0);
    });

    connection.start().catch(() => { /* hub unavailable */ });
    hubRef.current = connection;

    return () => {
      connection.stop();
      hubRef.current = null;
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return {
    permissions,
    loading,
    pathRefreshing,
    sectionLoadingTitles,
    sectionHasMore,
    isSectionLazy,
    loadSectionNavItems,
    loadMoreSectionNavItems,
    refresh,
  };
}
