import React, { useEffect, useRef, useState } from 'react';
import {
  SwitchCompanyModal,
  companyService,
  getActiveCompanyId,
  getAuthUser,
} from '@linm-soft/common-components';
import styles from './NavTopbarActions.module.css';

interface NavSwitchCompanyButtonProps {
  isMobile: boolean;
}

function resolveBranchLabel(
  item: { code?: string; shortName?: string; name: string } | undefined,
  companyId: string | null,
): string | null {
  if (!companyId) return null;
  if (item?.code) return item.code;
  if (item?.shortName) return item.shortName;
  if (item?.name) return item.name;
  return companyId.slice(0, 8);
}

/** Switch-company button + anchored popover — shows Mã chi nhánh đang làm việc. */
export const NavSwitchCompanyButton: React.FC<NavSwitchCompanyButtonProps> = ({ isMobile }) => {
  const [isOpen, setIsOpen] = useState(false);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const [label, setLabel] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const load = () => {
      const activeId = getActiveCompanyId() ?? getAuthUser()?.companyId ?? null;
      if (!activeId) {
        setLabel(null);
        return;
      }
      setLoading(true);
      companyService
        .getActiveList()
        .then((list) => {
          const user = getAuthUser();
          const filtered = user?.canViewAllCompanies
            ? list
            : list.filter((c) => {
                const allowed = new Set(user?.allowedCompanyIds ?? []);
                if (user?.companyId) allowed.add(user.companyId);
                return allowed.size === 0 || allowed.has(c.id);
              });
          setLabel(resolveBranchLabel(filtered.find((c) => c.id === activeId), activeId));
        })
        .catch(() => setLabel(activeId.slice(0, 8)))
        .finally(() => setLoading(false));
    };

    load();
    window.addEventListener('linm:company:changed', load);
    window.addEventListener('linm:auth:changed', load);
    return () => {
      window.removeEventListener('linm:company:changed', load);
      window.removeEventListener('linm:auth:changed', load);
    };
  }, []);

  const displayCode = label ?? '…';

  return (
    <>
      <button
        ref={buttonRef}
        type="button"
        className={styles.switchCompanyBtn}
        onClick={() => setIsOpen((open) => !open)}
        title={`Đơn vị cơ sở: ${displayCode}`}
        aria-label={`Đơn vị cơ sở đang làm việc: ${displayCode}. Nhấn để chuyển đổi.`}
        aria-expanded={isOpen}
        aria-haspopup="dialog"
        data-testid="nav-switch-company-btn"
      >
        <i className="fas fa-building" />
        {!isMobile && (
          <span className={styles.switchCompanyLabel}>
            {loading ? '…' : displayCode}
          </span>
        )}
      </button>
      <SwitchCompanyModal
        isOpen={isOpen}
        onClose={() => setIsOpen(false)}
        anchorRef={buttonRef}
      />
    </>
  );
};
