import React from 'react';
import {
  TopbarParcelSlot,
  TOPBAR_MESSAGE_PARCEL,
  TOPBAR_NOTIFICATION_PARCEL,
} from '@linm-soft/common-components';
import { appSettings } from '../config/appSettings';
import { NavSwitchCompanyButton } from './NavSwitchCompanyButton';

interface NavTopbarActionsProps {
  onNavigate: (path: string) => void;
  isAdmin: boolean;
  isMobile: boolean;
  allowedCompanyIds?: string[];
  canViewAllCompanies?: boolean;
}

/** Message + switch-company actions (Topbar rightSlot). */
export const NavTopbarRightActions: React.FC<NavTopbarActionsProps> = ({
  onNavigate,
  isAdmin,
  isMobile,
  allowedCompanyIds,
  canViewAllCompanies,
}) => (
  <>
    {(isAdmin || canViewAllCompanies || (allowedCompanyIds?.length ?? 0) > 1) && (
      <NavSwitchCompanyButton isMobile={isMobile} />
    )}
    {appSettings.enableMessage && (
      <TopbarParcelSlot link={TOPBAR_MESSAGE_PARCEL} customProps={{ onNavigate }} />
    )}
  </>
);

/** Notification bell (Topbar notificationSlot). Hidden when ENABLE_NOTIFICATION !== true. */
export const NavTopbarNotificationSlot: React.FC<Pick<NavTopbarActionsProps, 'onNavigate'>> = ({
  onNavigate,
}) =>
  appSettings.enableNotification ? (
    <TopbarParcelSlot link={TOPBAR_NOTIFICATION_PARCEL} customProps={{ onNavigate }} />
  ) : (
    <></>
  );
