import type { NavMenuItemDto } from '../hooks/useUserPermissions';

export const ADMIN_ROUTE_PREFIX = '/admin';

/** Static admin menu paths — allowed while permissions refetch for /admin. */
export const ADMIN_FALLBACK_PATHS = ['/admin/accounts', '/admin/permissions'] as const;

function normalizePath(path: string): string {
  if (!path) return '/';
  if (path === '/') return '/';
  return path.endsWith('/') ? path.slice(0, -1) : path;
}

function pathsFromNavItems(navItems: NavMenuItemDto[]): string[] {
  return navItems
    .map((item) => item.path)
    .filter((path): path is string => !!path && path !== '#')
    .map((path) => normalizePath(path));
}

/**
 * Route allow-list: prefer API `allowedPaths` (includes dynamic detail URLs),
 * else derive from loaded `navItems`.
 */
export function isPathAllowedByPermissions(
  pathname: string,
  navItems: NavMenuItemDto[],
  allowedPaths?: string[] | null,
  options?: { isAdminUser?: boolean },
): boolean {
  const normalizedPath = normalizePath(pathname);

  if (options?.isAdminUser && normalizedPath.startsWith(ADMIN_ROUTE_PREFIX)) {
    return true;
  }

  const allowed = (allowedPaths?.length ? allowedPaths : pathsFromNavItems(navItems)).map(
    (path) => normalizePath(path),
  );

  if (!allowed.length) return false;

  return allowed.some(
    (path) => normalizedPath === path || normalizedPath.startsWith(`${path}/`),
  );
}
